166→                            ctx.quadraticCurveTo(mx + perpX, my + perpY, posB.x, posB.y);
167→                            ctx.stroke();
168→                        }
169→                        ctx.shadowBlur = 0;
170→                    }}
171→                    perfectDrawEnabled={false}
172→                    listening={false}
173→                />
174→            )}
175→            {/* Spiral galaxy visuals + connection lines */}
176→            <Shape
177→                sceneFunc={(ctx) => { drawGalaxyVisuals(ctx, galaxyVisuals, galaxyEdges, galaxyUserIdMap); }}
