  1→import React, { useRef, useEffect, useCallback, useMemo } from 'react';
  2→import { Layer, Shape } from 'react-konva';
  3→import { STAR_COLORS } from '../utils/starUtils';
  4→
  5→const TWO_PI = Math.PI * 2;
  6→const RING_COUNT = 4;
  7→const SPIRAL_ARMS = 3;
  8→const SPIRAL_PARTICLES = 16;
  9→const OUTER_PARTICLE_COUNT = 14;
 10→
 11→/** Parse "#5f92ff" → { r, g, b } */
 12→const parseHex = (hex) => ({
 13→    r: parseInt(hex.slice(1, 3), 16),
 14→    g: parseInt(hex.slice(3, 5), 16),
 15→    b: parseInt(hex.slice(5, 7), 16),
 16→});
 17→
 18→/** Lerp between two RGB colors */
 19→const lerpRgb = (a, b, t) => ({
 20→    r: Math.round(a.r + (b.r - a.r) * t),
 21→    g: Math.round(a.g + (b.g - a.g) * t),
 22→    b: Math.round(a.b + (b.b - a.b) * t),
 23→});
 24→
 25→const WHITE = { r: 255, g: 255, b: 255 };
 26→
 27→const WormholeLayer = React.memo(({ layerProps, wormholes, zoom }) => {
 28→    const animRef = useRef({ time: 0 });
 29→    const shapeRef = useRef(null);
 30→    const rafRef = useRef(null);
 31→
 32→    // Always bright
 33→    const opacity = zoom < 0.15 ? 1.0
 34→        : zoom < 1.0 ? 1.0 - (zoom - 0.15) * 0.2
 35→        : 0.83;
 36→
 37→    // Pre-compute vortex data with colors and stable phase offsets
 38→    const vortexData = useMemo(() => {
 39→        if (!Array.isArray(wormholes)) return [];
 40→        return wormholes.map((wh, i) => {
 41→            const color = STAR_COLORS[i % STAR_COLORS.length];
 42→            const rgb = parseHex(color);
 43→            const hashVal = wh.post_a ? parseInt(wh.post_a.slice(0, 8), 16) : i * 12345;
 44→            return {
 45→                ...wh,
 46→                color,
 47→                rgb,
 48→                phaseA: (hashVal % 1000) / 1000 * TWO_PI,
 49→                phaseB: ((hashVal * 7) % 1000) / 1000 * TWO_PI,
 50→            };
 51→        });
 52→    }, [wormholes]);
 53→
 54→    const animate = useCallback(() => {
 55→        animRef.current.time = performance.now();
 56→        if (shapeRef.current) {
 57→            shapeRef.current.getLayer()?.batchDraw();
 58→        }
 59→        rafRef.current = requestAnimationFrame(animate);
 60→    }, []);
 61→
 62→    useEffect(() => {
 63→        if (vortexData.length === 0) return;
 64→        rafRef.current = requestAnimationFrame(animate);
 65→        return () => {
 66→            if (rafRef.current) cancelAnimationFrame(rafRef.current);
 67→        };
 68→    }, [animate, vortexData.length]);
 69→
 70→    if (vortexData.length === 0) return null;
 71→
 72→    const drawVortex = (ctx, x, y, rgb, time, phaseOffset, radius) => {
 73→        const breathe = 1.0 + 0.25 * Math.sin(time * 0.001 + phaseOffset);
 74→        const r = radius * breathe;
 75→
 76→        // Large pulsing outer halo — makes it unmissable
 77→        const pulseScale = 1.0 + 0.3 * Math.sin(time * 0.0015 + phaseOffset);
 78→        const haloR = r * 4.0 * pulseScale;
 79→        const haloGrad = ctx.createRadialGradient(x, y, 0, x, y, haloR);
 80→        haloGrad.addColorStop(0, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.25 * opacity})`);
 81→        haloGrad.addColorStop(0.3, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.12 * opacity})`);
 82→        haloGrad.addColorStop(0.6, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.04 * opacity})`);
 83→        haloGrad.addColorStop(1, 'rgba(0,0,0,0)');
 84→        ctx.beginPath();
 85→        ctx.arc(x, y, haloR, 0, TWO_PI);
 86→        ctx.fillStyle = haloGrad;
 87→        ctx.fill();
 88→
 89→        // Inner bright glow
 90→        const innerGlow = ctx.createRadialGradient(x, y, 0, x, y, r * 1.8);
 91→        innerGlow.addColorStop(0, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.45 * opacity})`);
 92→        innerGlow.addColorStop(0.4, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.2 * opacity})`);
 93→        innerGlow.addColorStop(1, 'rgba(0,0,0,0)');
 94→        ctx.beginPath();
 95→        ctx.arc(x, y, r * 1.8, 0, TWO_PI);
 96→        ctx.fillStyle = innerGlow;
 97→        ctx.fill();
 98→
 99→        // Dark center void (the "hole")
100→        const voidGrad = ctx.createRadialGradient(x, y, 0, x, y, r * 0.4);
101→        voidGrad.addColorStop(0, `rgba(0,0,0,${0.85 * opacity})`);
102→        voidGrad.addColorStop(0.6, `rgba(0,0,0,${0.4 * opacity})`);
103→        voidGrad.addColorStop(1, 'rgba(0,0,0,0)');
104→        ctx.beginPath();
105→        ctx.arc(x, y, r * 0.4, 0, TWO_PI);
106→        ctx.fillStyle = voidGrad;
107→        ctx.fill();
108→
109→        // Bright event horizon ring
110→        const ehRadius = r * 0.48;
111→        const ehAlpha = (0.6 + 0.2 * Math.sin(time * 0.002 + phaseOffset)) * opacity;
112→        ctx.beginPath();
113→        ctx.arc(x, y, ehRadius, 0, TWO_PI);
114→        ctx.strokeStyle = `rgba(255,255,255,${ehAlpha})`;
115→        ctx.lineWidth = 2.5;
116→        ctx.stroke();
117→
118→        // Concentric rotating rings
119→        for (let ring = 0; ring < RING_COUNT; ring++) {
120→            const ringRadius = r * (0.6 + ring * 0.3);
121→            const rotSpeed = 0.0008 * (ring % 2 === 0 ? 1 : -1) * (1 + ring * 0.25);
122→            const rot = time * rotSpeed + phaseOffset + ring * 0.7;
123→            const ringAlpha = (0.55 - ring * 0.08) * opacity;
124→
125→            const segments = 5 + ring * 2;
126→            const gapRatio = 0.3;
127→            const segSweep = TWO_PI / segments * (1 - gapRatio);
128→
129→            ctx.lineWidth = Math.max(2.5 - ring * 0.4, 1.0);
130→            const c = lerpRgb(rgb, WHITE, 0.35 - ring * 0.06);
131→            ctx.strokeStyle = `rgba(${c.r},${c.g},${c.b},${ringAlpha})`;
132→
133→            for (let s = 0; s < segments; s++) {
134→                const start = rot + (s * TWO_PI / segments);
135→                ctx.beginPath();
136→                ctx.arc(x, y, ringRadius, start, start + segSweep);
137→                ctx.stroke();
138→            }
139→        }
140→
141→        // Spiral arms — particles spiraling inward
142→        for (let arm = 0; arm < SPIRAL_ARMS; arm++) {
143→            const armOffset = (arm * TWO_PI) / SPIRAL_ARMS;
144→            for (let p = 0; p < SPIRAL_PARTICLES; p++) {
145→                const t = p / SPIRAL_PARTICLES;
146→                const spiralAngle = armOffset + t * TWO_PI * 2.0 + time * 0.0015 + phaseOffset;
147→                const spiralR = r * (0.25 + t * 1.2);
148→                const px = x + Math.cos(spiralAngle) * spiralR;
149→                const py = y + Math.sin(spiralAngle) * spiralR;
150→                const pAlpha = (0.3 + 0.5 * (1 - t)) * opacity;
151→                const pSize = 1.5 + 2.5 * (1 - t);
152→
153→                ctx.beginPath();
154→                ctx.arc(px, py, pSize, 0, TWO_PI);
155→                const pc = lerpRgb(rgb, WHITE, 0.6 * (1 - t));
156→                ctx.fillStyle = `rgba(${pc.r},${pc.g},${pc.b},${pAlpha})`;
157→                ctx.fill();
158→            }
159→        }
160→
161→        // Outer orbiting particles — larger, brighter
162→        for (let p = 0; p < OUTER_PARTICLE_COUNT; p++) {
163→            const orbitSpeed = 0.0005 + (p % 4) * 0.00015;
164→            const dir = p % 2 === 0 ? 1 : -1;
165→            const orbitR = r * (1.3 + (p / OUTER_PARTICLE_COUNT) * 1.0);
166→            const angle = time * orbitSpeed * dir + phaseOffset + (p * TWO_PI / OUTER_PARTICLE_COUNT);
167→            const px = x + Math.cos(angle) * orbitR;
168→            const py = y + Math.sin(angle) * orbitR;
169→            const pAlpha = (0.5 + 0.3 * Math.sin(time * 0.003 + p * 1.1)) * opacity;
170→
171→            ctx.beginPath();
172→            ctx.arc(px, py, 2.0, 0, TWO_PI);
173→            ctx.fillStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${pAlpha})`;
174→            ctx.fill();
175→        }
176→
177→        // Bright core — white hot center
178→        const coreGrad = ctx.createRadialGradient(x, y, 0, x, y, r * 0.2);
179→        coreGrad.addColorStop(0, `rgba(255,255,255,${0.95 * opacity})`);
180→        coreGrad.addColorStop(0.4, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.6 * opacity})`);
181→        coreGrad.addColorStop(1, 'rgba(0,0,0,0)');
182→        ctx.beginPath();
183→        ctx.arc(x, y, r * 0.2, 0, TWO_PI);
184→        ctx.fillStyle = coreGrad;
185→        ctx.fill();
186→    };
187→
188→    const drawConnection = (ctx, ax, ay, bx, by, rgb, time) => {
189→        const dx = bx - ax;
190→        const dy = by - ay;
191→        const dist = Math.sqrt(dx * dx + dy * dy) || 1;
192→
193→        const mx = (ax + bx) / 2;
194→        const my = (ay + by) / 2;
195→        const perpX = (-dy / dist) * dist * 0.08;
196→        const perpY = (dx / dist) * dist * 0.08;
197→
198→        const dashPhase = time * 0.06;
199→
200→        // Glow line underneath
201→        ctx.save();
202→        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${0.06 * opacity})`;
203→        ctx.lineWidth = 4;
204→        ctx.beginPath();
205→        ctx.moveTo(ax, ay);
206→        ctx.quadraticCurveTo(mx + perpX, my + perpY, bx, by);
207→        ctx.stroke();
208→
209→        // Dashed bright line
210→        ctx.setLineDash([10, 14]);
211→        ctx.lineDashOffset = -dashPhase;
212→        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${0.2 * opacity})`;
213→        ctx.lineWidth = 1.5;
214→        ctx.beginPath();
215→        ctx.moveTo(ax, ay);
216→        ctx.quadraticCurveTo(mx + perpX, my + perpY, bx, by);
217→        ctx.stroke();
218→        ctx.setLineDash([]);
219→        ctx.restore();
220→    };
221→
222→    // Bigger base radius — scales with zoom to stay prominent
223→    const vortexRadius = Math.max(30, Math.min(70, 45 / zoom));
224→
225→    return (
226→        <Layer {...layerProps} listening={false}>
227→            <Shape
228→                ref={shapeRef}
229→                sceneFunc={(ctx) => {
230→                    const time = animRef.current.time;
231→                    for (const vortex of vortexData) {
232→                        drawConnection(ctx, vortex.a_x, vortex.a_y, vortex.b_x, vortex.b_y, vortex.rgb, time);
233→                        drawVortex(ctx, vortex.a_x, vortex.a_y, vortex.rgb, time, vortex.phaseA, vortexRadius);
234→                        drawVortex(ctx, vortex.b_x, vortex.b_y, vortex.rgb, time, vortex.phaseB, vortexRadius);
235→                    }
236→                }}
237→                perfectDrawEnabled={false}
238→                listening={false}
239→            />
240→        </Layer>
241→    );
242→});
